17: const codeMigration = "code migration"
18: 
19: type MigrationError struct {
20: 	AlertId int64
21: 	Err     error
22: }
23: 
24: func (e MigrationError) Error() string {
25: 	return fmt.Sprintf("failed to migrate alert %d: %s", e.AlertId, e.Err.Error())
26: }
