91: type AlertConfiguration struct {
92: 	ID    int64 `xorm:"pk autoincr 'id'"`
93: 	OrgID int64 `xorm:"org_id"`
94: 
95: 	AlertmanagerConfiguration string
96: 	ConfigurationVersion      string
97: 	CreatedAt                 int64 `xorm:"created"`
98: }
